class ParkingSystem {
    int bigSlots;
    int mediumSlots;
    int smallSlots;

    public ParkingSystem(int big, int medium, int small) {
        bigSlots = big;
        mediumSlots = medium;
        smallSlots = small;
    }

    public boolean addCar(int carType) {
        if (carType == 1) {
            if (bigSlots > 0) {
                bigSlots--;
                return true;
            }
        } else if (carType == 2) {
            if (mediumSlots > 0) {
                mediumSlots--;
                return true;
            }
        } else {
            if (smallSlots > 0) {
                smallSlots--;
                return true;
            }
        }
        return false;
    }
}

efficiency: HIGH
time complexity: O(1)
space complexity: O(1)
energy implications: LOW

